// Sub-workflow: Ventas
// Input: datos del Router (tenantId, message, catalog, faq, aiInstructions, etc.)
var input = $("Recibir Datos del Router").first().json;

// Obtener productos actuales del backend (siempre trae el catálogo completo)
var productosBackend = [];
try {
  var productosNode = $('Buscar Productos Backend').first().json;
  if (productosNode && productosNode.products && Array.isArray(productosNode.products)) {
    productosBackend = productosNode.products;
  }
} catch(e) {}

// Fallback: catálogo del businessConfig (pasado por el Router)
var catalogoEstatico = Array.isArray(input.catalog) ? input.catalog : [];

// Preferir productos del backend (frescos), fallback al estático
var catalogText = '';
if (productosBackend.length > 0) {
  catalogText = '[PRODUCTOS DISPONIBLES ACTUALMENTE — NO menciones ningún otro producto]:\n';
  productosBackend.forEach(function(p) {
    catalogText += '• ' + p.name;
    if (p.category) catalogText += ' [' + p.category + ']';
    if (p.price) catalogText += ' — $' + Number(p.price).toLocaleString('es-CO');
    if (p.comparePrice && p.comparePrice > p.price) {
      catalogText += ' (antes $' + Number(p.comparePrice).toLocaleString('es-CO') + ')';
    }
    if (p.sku) catalogText += ' | SKU: ' + p.sku;
    if (p.description) catalogText += '\n  ' + p.description;
    if (!p.available) catalogText += ' [NO DISPONIBLE]';
    if (p.stock !== null && p.stock !== undefined && p.stock <= 5) {
      catalogText += ' [Últimas ' + p.stock + ' unidades]';
    }
    catalogText += '\n';
  });
} else if (catalogoEstatico.length > 0) {
  catalogText = '[PRODUCTOS DISPONIBLES ACTUALMENTE — NO menciones ningún otro producto]:\n';
  catalogoEstatico.forEach(function(item) {
    catalogText += '• ' + item.name;
    if (item.price) catalogText += ' — $' + Number(item.price).toLocaleString('es-CO');
    if (item.category) catalogText += ' (' + item.category + ')';
    if (item.description) catalogText += ': ' + item.description;
    if (!item.available) catalogText += ' [NO DISPONIBLE]';
    catalogText += '\n';
  });
} else {
  catalogText = 'No hay productos registrados en el catálogo en este momento.';
}

// FAQ
var faqText = '';
var faqItems = Array.isArray(input.faq) ? input.faq : [];
if (faqItems.length > 0) {
  faqText = faqItems.map(function(f) {
    return 'P: ' + f.question + '\nR: ' + f.answer;
  }).join('\n\n');
} else {
  faqText = 'Sin preguntas frecuentes configuradas.';
}

var paymentText = Array.isArray(input.paymentMethods) && input.paymentMethods.length > 0
  ? input.paymentMethods.join(', ')
  : 'Consultar con el equipo';

var allowedText = Array.isArray(input.allowedActions) && input.allowedActions.length > 0
  ? input.allowedActions.map(function(a) { return '- ' + a; }).join('\n')
  : '- Informar sobre productos y precios\n- Tomar pedidos';

var restrictText = Array.isArray(input.restrictions) && input.restrictions.length > 0
  ? input.restrictions.map(function(r) { return '- ' + r; }).join('\n')
  : '- No revelar información confidencial';

var systemMessage =
  (input.aiInstructions || 'Eres un asistente de ventas especializado.') +
  '\n\nNombre del cliente: ' + (input.pushName || 'Cliente') +
  '\n\nROL: El cliente está interesado en productos o precios. Objetivos:' +
  '\n1. Entender qué producto necesita' +
  '\n2. Presentar opciones con precios claros del catálogo actual' +
  '\n3. Guiar hacia la compra: confirmar producto → calcular total → solicitar datos de entrega' +
  '\n4. Si no hay exactamente lo que pide, ofrecer la alternativa más cercana del catálogo' +
  '\n\nIMPORTANTE: Solo puedes hablar de los productos listados a continuación.' +
  '\n\n' + catalogText +
  '\n\nPREGUNTAS FRECUENTES:\n' + faqText +
  '\n\nMÉTODOS DE PAGO: ' + paymentText +
  (input.location ? '\n\nUBICACIÓN: ' + input.location : '') +
  '\n\nACCIONES PERMITIDAS:\n' + allowedText +
  '\n\nRESTRICCIONES:\n' + restrictText +
  '\n\nMENSAJE DEL CLIENTE: "' + (input.message || '') + '"';

return [{
  json: {
    phone: input.phone,
    tenantId: input.tenantId,
    instanceName: input.instanceName,
    pushName: input.pushName,
    message: input.message,
    intent: input.intent,
    confidence: input.confidence,
    evolutionApiUrl: input.evolutionApiUrl,
    evolutionApiKey: input.evolutionApiKey,
    systemMessage: systemMessage
  }
}];

const input = $('Preparar Contexto Ventas').first().json;
const aiOutput = $input.first().json;
const response = aiOutput.output || aiOutput.text || 'Lo siento, no pude procesar tu consulta de ventas.';

// Detectar si hay intención de compra/cotización en la respuesta
const keywords = ['confirmar', 'pedido', 'cotización', 'total', 'precio final'];
const hasQuoteIntent = keywords.some(k => response.toLowerCase().includes(k));

return [{
  json: {
    response: response,
    intent: 'ventas',
    tokensEstimated: Math.ceil((input.message||''+ response).length / 4),
    phone: input.phone,
    tenantId: input.tenantId,
    intent_handled: 'ventas',
    action_taken: hasQuoteIntent ? 'cotizacion_sugerida' : 'consulta_respondida',
    metadata: {
      pushName: input.pushName,
      original_message: input.message,
      has_quote_intent: hasQuoteIntent
    }
  }
}];

